/* =========================================================================
   style.css — OBS コメントオーバーレイ スタイルシート
   =========================================================================
   ページ全体は常に透明にしておくこと（OBS のブラウザソースで
   背景がそのまま透過表示されるようにするため）。
   ========================================================================= */

html, body {
  margin: 0;
  padding: 0;
  width: 100%;
  height: 100%;
  background: transparent !important;
  overflow: hidden;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

* {
  box-sizing: border-box;
}

/* -------------------------------------------------------------------------
   コメント表示用コンテナ（画面の四隅いずれかに固定）
   ------------------------------------------------------------------------- */
#comment-stack {
  position: fixed;
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-width: 560px;
  padding: 28px;
  pointer-events: none;
  z-index: 9999;
}

/* 縦位置 */
#comment-stack.pos-top {
  top: 0;
  flex-direction: column;
}
#comment-stack.pos-bottom {
  bottom: 0;
  flex-direction: column-reverse;
}

/* 横位置 */
#comment-stack.pos-left {
  left: 0;
  align-items: flex-start;
}
#comment-stack.pos-right {
  right: 0;
  align-items: flex-end;
}

/* -------------------------------------------------------------------------
   コメントカード本体
   ------------------------------------------------------------------------- */
.comment-card {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  width: 100%;
  padding: 14px 18px;
  border-radius: 18px;
  box-shadow: 0 6px 18px rgba(0, 0, 0, 0.35), 0 1px 3px rgba(0, 0, 0, 0.25);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  opacity: 0;
  will-change: transform, opacity;
}

/* スライドイン方向は左右配置に応じて切り替える（JSがクラスを付与） */
.comment-card.slide-from-left {
  animation-name: slideInFromLeft;
}
.comment-card.slide-from-right {
  animation-name: slideInFromRight;
}
.comment-card.anim-in {
  animation-timing-function: cubic-bezier(0.22, 1, 0.36, 1);
  animation-fill-mode: forwards;
}
.comment-card.anim-out {
  animation-name: fadeOutDown;
  animation-timing-function: ease-in;
  animation-fill-mode: forwards;
}

@keyframes slideInFromLeft {
  0%   { opacity: 0; transform: translateX(-60px) scale(0.96); }
  60%  { opacity: 1; transform: translateX(6px) scale(1.01); }
  100% { opacity: 1; transform: translateX(0) scale(1); }
}

@keyframes slideInFromRight {
  0%   { opacity: 0; transform: translateX(60px) scale(0.96); }
  60%  { opacity: 1; transform: translateX(-6px) scale(1.01); }
  100% { opacity: 1; transform: translateX(0) scale(1); }
}

@keyframes fadeOutDown {
  0%   { opacity: 1; transform: translateY(0) scale(1); }
  100% { opacity: 0; transform: translateY(14px) scale(0.94); }
}

/* -------------------------------------------------------------------------
   アバター（アイコン円）
   ------------------------------------------------------------------------- */
.comment-avatar {
  flex: 0 0 auto;
  width: 44px;
  height: 44px;
  border-radius: 50%;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 18px;
  background: linear-gradient(135deg, #7c6cf6, #4ec9ff);
  color: #fff;
  border: 2px solid rgba(255, 255, 255, 0.55);
  flex-shrink: 0;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.4);
}

.comment-avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* -------------------------------------------------------------------------
   本文エリア
   ------------------------------------------------------------------------- */
.comment-body {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.comment-name {
  font-weight: 700;
  font-size: 14px;
  line-height: 1.3;
  letter-spacing: 0.2px;
}

.comment-text {
  font-size: 16px;
  line-height: 1.45;
  word-break: break-word;
  overflow-wrap: anywhere;
  white-space: pre-wrap;
}

/* =========================================================================
   テーマ: theme-dark （暗め・標準）
   ========================================================================= */
body.theme-dark .comment-card {
  background: rgba(24, 24, 32, 0.82);
  border: 1px solid rgba(255, 255, 255, 0.08);
}
body.theme-dark .comment-name {
  color: #8ad8ff;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.6);
}
body.theme-dark .comment-text {
  color: #f5f5f7;
  text-shadow: 0 1px 3px rgba(0, 0, 0, 0.7);
}

/* =========================================================================
   テーマ: theme-light （明るめ）
   ========================================================================= */
body.theme-light .comment-card {
  background: rgba(255, 255, 255, 0.92);
  border: 1px solid rgba(0, 0, 0, 0.08);
  box-shadow: 0 6px 18px rgba(0, 0, 0, 0.18), 0 1px 3px rgba(0, 0, 0, 0.12);
}
body.theme-light .comment-name {
  color: #2563eb;
  text-shadow: none;
}
body.theme-light .comment-text {
  color: #1f2430;
  text-shadow: none;
}
body.theme-light .comment-avatar {
  border-color: rgba(0, 0, 0, 0.15);
}

/* =========================================================================
   テーマ: theme-neon （ネオン発光風）
   ========================================================================= */
body.theme-neon .comment-card {
  background: rgba(10, 8, 20, 0.78);
  border: 1px solid rgba(255, 0, 200, 0.55);
  box-shadow:
    0 0 12px rgba(255, 0, 200, 0.55),
    0 0 28px rgba(80, 220, 255, 0.35),
    0 4px 14px rgba(0, 0, 0, 0.5);
}
body.theme-neon .comment-name {
  color: #ff4fd8;
  text-shadow: 0 0 6px rgba(255, 79, 216, 0.9), 0 0 14px rgba(255, 79, 216, 0.5);
}
body.theme-neon .comment-text {
  color: #d9fbff;
  text-shadow: 0 0 4px rgba(80, 220, 255, 0.6);
}
body.theme-neon .comment-avatar {
  background: linear-gradient(135deg, #ff4fd8, #4fe1ff);
  border-color: rgba(255, 255, 255, 0.7);
  box-shadow: 0 0 10px rgba(79, 225, 255, 0.8);
}

/* -------------------------------------------------------------------------
   小さな画面・縮小時にも文字が見切れないように
   ------------------------------------------------------------------------- */
@media (max-width: 480px) {
  #comment-stack {
    max-width: 90vw;
    padding: 14px;
  }
}

/* =========================================================================
   app.js — コメントオーバーレイ エンジン本体
   =========================================================================
   このファイルは編集不要です（設定変更は config.js で行ってください）。

   提供機能:
   - config.js の設定を読み込み、テーマ／位置／表示数などを適用
   - "demo" モード: ダミーの日本語コメントを自動生成
   - "websocket" モード: 指定 URL に接続し、JSON コメントを受信
       受信メッセージ形式: {"name":"...", "text":"...", "icon":"..."}
   - window.addComment({name, text, icon}) をグローバルに公開
     → 他の外部スクリプトや拡張からも直接コメントを追加できる
   ========================================================================= */

(function () {
  "use strict";

  // -----------------------------------------------------------------------
  // 設定の読み込み（config.js が読み込まれていない場合のフォールバックも用意）
  // -----------------------------------------------------------------------
  var DEFAULTS = {
    theme: "theme-dark",
    maxComments: 6,
    commentLifetimeMs: 8000,
    animationSpeedMs: 450,
    fontFamily: "'Yu Gothic UI', 'Hiragino Sans', 'Meiryo', sans-serif",
    verticalPosition: "bottom",
    horizontalPosition: "left",
    mode: "demo",
    websocketUrl: "ws://localhost:8080",
    reconnectIntervalMs: 3000,
    demoIntervalMinMs: 1800,
    demoIntervalMaxMs: 4000
  };

  var userConfig = (window.OVERLAY_CONFIG && typeof window.OVERLAY_CONFIG === "object")
    ? window.OVERLAY_CONFIG
    : {};

  var CONFIG = {};
  for (var key in DEFAULTS) {
    CONFIG[key] = (userConfig[key] !== undefined) ? userConfig[key] : DEFAULTS[key];
  }

  // -----------------------------------------------------------------------
  // 初期セットアップ: body へのテーマ・フォント適用、コンテナの配置
  // -----------------------------------------------------------------------
  var VALID_THEMES = ["theme-dark", "theme-light", "theme-neon"];
  var theme = VALID_THEMES.indexOf(CONFIG.theme) !== -1 ? CONFIG.theme : DEFAULTS.theme;

  document.body.classList.remove("theme-dark", "theme-light", "theme-neon");
  document.body.classList.add(theme);
  document.body.style.fontFamily = CONFIG.fontFamily;

  var stack = document.getElementById("comment-stack");
  if (!stack) {
    stack = document.createElement("div");
    stack.id = "comment-stack";
    document.body.appendChild(stack);
  }

  var vPos = (CONFIG.verticalPosition === "top") ? "top" : "bottom";
  var hPos = (CONFIG.horizontalPosition === "right") ? "right" : "left";
  stack.classList.add("pos-" + vPos, "pos-" + hPos);

  // アニメーション速度を CSS カスタムプロパティ経由で反映
  document.documentElement.style.setProperty(
    "--anim-speed", CONFIG.animationSpeedMs + "ms"
  );

  var slideClass = (hPos === "right") ? "slide-from-right" : "slide-from-left";

  // -----------------------------------------------------------------------
  // ユーティリティ
  // -----------------------------------------------------------------------
  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function pickInitial(name) {
    if (!name) return "?";
    var trimmed = String(name).trim();
    if (!trimmed) return "?";
    // サロゲートペア（絵文字等）を考慮して最初の1文字を取得
    var firstChar = Array.from(trimmed)[0];
    return firstChar.toUpperCase();
  }

  function avatarColorFromString(str) {
    var hash = 0;
    for (var i = 0; i < str.length; i++) {
      hash = (hash << 5) - hash + str.charCodeAt(i);
      hash |= 0;
    }
    var hue1 = Math.abs(hash) % 360;
    var hue2 = (hue1 + 55) % 360;
    return "linear-gradient(135deg, hsl(" + hue1 + ",75%,60%), hsl(" + hue2 + ",75%,55%))";
  }

  // -----------------------------------------------------------------------
  // コメントカードの生成・自動削除
  // -----------------------------------------------------------------------
  var activeCards = [];

  function removeCard(card) {
    if (!card || card._removing) return;
    card._removing = true;
    card.classList.remove("anim-in", slideClass);
    card.classList.add("anim-out");
    card.style.animationDuration = CONFIG.animationSpeedMs + "ms";

    var cleanup = function () {
      if (card.parentNode) card.parentNode.removeChild(card);
      var idx = activeCards.indexOf(card);
      if (idx !== -1) activeCards.splice(idx, 1);
    };
    card.addEventListener("animationend", cleanup, { once: true });
    // フォールバック（animationend が発火しない異常系への保険）
    setTimeout(cleanup, CONFIG.animationSpeedMs + 400);
  }

  function enforceMaxComments() {
    var max = Math.max(1, parseInt(CONFIG.maxComments, 10) || DEFAULTS.maxComments);
    while (activeCards.length > max) {
      removeCard(activeCards[0]);
    }
  }

  /**
   * 画面にコメントカードを1件追加する。
   * @param {Object} data - { name, text, icon }
   */
  function renderComment(data) {
    var name = (data && data.name) ? String(data.name) : "名無し";
    var text = (data && data.text !== undefined && data.text !== null) ? String(data.text) : "";
    var icon = (data && data.icon) ? String(data.icon) : "";

    if (!text.trim() && !name.trim()) return; // 完全に空のメッセージは無視

    var card = document.createElement("div");
    card.className = "comment-card " + slideClass;
    card.style.animationDuration = CONFIG.animationSpeedMs + "ms";

    // アバター
    var avatar = document.createElement("div");
    avatar.className = "comment-avatar";

    if (icon) {
      var img = document.createElement("img");
      img.src = icon;
      img.alt = "";
      img.referrerPolicy = "no-referrer";
      img.onerror = function () {
        // 画像読み込み失敗時は文字アバターにフォールバック
        avatar.innerHTML = "";
        avatar.style.background = avatarColorFromString(name);
        avatar.textContent = pickInitial(name);
      };
      avatar.appendChild(img);
    } else {
      avatar.style.background = avatarColorFromString(name);
      avatar.textContent = pickInitial(name);
    }

    // 本文
    var body = document.createElement("div");
    body.className = "comment-body";

    var nameEl = document.createElement("div");
    nameEl.className = "comment-name";
    nameEl.textContent = name;

    var textEl = document.createElement("div");
    textEl.className = "comment-text";
    textEl.textContent = text; // textContent によりHTML注入を防止しつつ絵文字はそのまま表示

    body.appendChild(nameEl);
    body.appendChild(textEl);

    card.appendChild(avatar);
    card.appendChild(body);

    // アニメーション開始のためフレームを1つ待つ
    requestAnimationFrame(function () {
      card.classList.add("anim-in");
    });

    stack.appendChild(card);
    activeCards.push(card);

    enforceMaxComments();

    var lifetime = Math.max(1000, parseInt(CONFIG.commentLifetimeMs, 10) || DEFAULTS.commentLifetimeMs);
    card._timeoutId = setTimeout(function () {
      removeCard(card);
    }, lifetime);
  }

  // -----------------------------------------------------------------------
  // グローバル公開 API: window.addComment({name, text, icon})
  // -----------------------------------------------------------------------
  window.addComment = function (data) {
    try {
      renderComment(data || {});
    } catch (err) {
      console.error("[overlay] addComment 失敗:", err);
    }
  };

  // -----------------------------------------------------------------------
  // デモモード: ランダムな日本語コメントを自動生成
  // -----------------------------------------------------------------------
  var DEMO_NAMES = [
    "ねこ太郎", "ゲーム好き٩(ˊᗜˋ*)و", "通りすがりの視聴者", "もちもちうさぎ",
    "夜更かしリスナー", "コーヒー中毒者", "初見です", "常連さん",
    "プログラマー見習い", "VTuberファン", "深夜の住人", "推し活民"
  ];

  var DEMO_MESSAGES = [
    "こんばんは〜！今日も配信楽しみにしてました✨",
    "うおおおおすごい！！🎉",
    "それ前にも見たことあるｗｗｗ",
    "初見です、よろしくお願いします😊",
    "今日のBGMいいですね🎵",
    "草",
    "がんばえー！応援してます💪",
    "それは無理じゃないですか？😂",
    "神プレイすぎる…",
    "コメント読んでくれてありがとうございます🙏",
    "次の配信も楽しみにしてます！",
    "もう少しでクリアできそう！",
    "画質きれい〜",
    "声がいい感じに通ってます🎤",
    "おつかれさまです、また来ます👋",
    "そこ右ですよ！右！！",
    "BGMの音量ちょうどいいですね",
    "やったー！おめでとうございます🎊",
    "今日は何時まで配信しますか？",
    "全然気づかなかった…さすが"
  ];

  var demoTimerId = null;

  function scheduleDemoComment() {
    var min = Math.max(200, parseInt(CONFIG.demoIntervalMinMs, 10) || DEFAULTS.demoIntervalMinMs);
    var max = Math.max(min, parseInt(CONFIG.demoIntervalMaxMs, 10) || DEFAULTS.demoIntervalMaxMs);
    var delay = min + Math.random() * (max - min);

    demoTimerId = setTimeout(function () {
      var name = DEMO_NAMES[Math.floor(Math.random() * DEMO_NAMES.length)];
      var text = DEMO_MESSAGES[Math.floor(Math.random() * DEMO_MESSAGES.length)];
      window.addComment({ name: name, text: text, icon: "" });
      scheduleDemoComment();
    }, delay);
  }

  function startDemoMode() {
    // 起動直後に最初のコメントをすぐ表示してから、ランダム間隔で続ける
    window.addComment({
      name: "デモモード",
      text: "これはデモ表示です。config.js の mode を \"websocket\" に変更すると実際のコメントを受信できます。",
      icon: ""
    });
    scheduleDemoComment();
  }

  function stopDemoMode() {
    if (demoTimerId) {
      clearTimeout(demoTimerId);
      demoTimerId = null;
    }
  }

  // -----------------------------------------------------------------------
  // WebSocket モード: 指定URLに接続しJSONコメントを受信、切断時は自動再接続
  // -----------------------------------------------------------------------
  var ws = null;
  var wsReconnectTimerId = null;
  var wsClosedByUser = false;

  function connectWebSocket() {
    if (!CONFIG.websocketUrl) {
      console.warn("[overlay] websocketUrl が設定されていません。");
      return;
    }

    try {
      ws = new WebSocket(CONFIG.websocketUrl);
    } catch (err) {
      console.error("[overlay] WebSocket 接続エラー:", err);
      scheduleReconnect();
      return;
    }

    ws.onopen = function () {
      console.log("[overlay] WebSocket 接続成功: " + CONFIG.websocketUrl);
    };

    ws.onmessage = function (event) {
      var payload;
      try {
        payload = JSON.parse(event.data);
      } catch (err) {
        console.warn("[overlay] JSON解析に失敗したメッセージを無視:", event.data);
        return;
      }

      // 単体オブジェクト、または配列での一括送信の両方に対応
      if (Array.isArray(payload)) {
        payload.forEach(function (item) {
          window.addComment(item);
        });
      } else {
        window.addComment(payload);
      }
    };

    ws.onerror = function (err) {
      console.warn("[overlay] WebSocket エラー:", err);
    };

    ws.onclose = function () {
      ws = null;
      if (!wsClosedByUser) {
        console.warn("[overlay] WebSocket が切断されました。再接続を試みます…");
        scheduleReconnect();
      }
    };
  }

  function scheduleReconnect() {
    if (wsReconnectTimerId) return;
    var interval = Math.max(500, parseInt(CONFIG.reconnectIntervalMs, 10) || DEFAULTS.reconnectIntervalMs);
    wsReconnectTimerId = setTimeout(function () {
      wsReconnectTimerId = null;
      connectWebSocket();
    }, interval);
  }

  function startWebSocketMode() {
    wsClosedByUser = false;
    connectWebSocket();
  }

  // -----------------------------------------------------------------------
  // 起動: config.mode に応じてモードを開始
  // -----------------------------------------------------------------------
  function init() {
    if (CONFIG.mode === "websocket") {
      startWebSocketMode();
    } else {
      startDemoMode();
    }
  }

  if (document.readyState === "complete" || document.readyState === "interactive") {
    init();
  } else {
    document.addEventListener("DOMContentLoaded", init);
  }

  // デバッグ・拡張用に内部状態を露出（任意）
  window.__overlay = {
    config: CONFIG,
    stopDemoMode: stopDemoMode,
    startDemoMode: startDemoMode
  };

})();

